package com.google.gson.metrics;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.lang.reflect.Method;
import java.net.URL;
import java.nio.file.Path;

public class ParseBenchmarkTest {

  @TempDir
  Path tempDir;

  @Test
  public void testGetResourceFile_validFile() throws Exception {
    // Arrange: create a temporary file and get its resource URL
    File tempFile = tempDir.resolve("testfile.txt").toFile();
    assertTrue(tempFile.createNewFile());

    // Use the tempFile's URI to create a URL and register it as a resource
    // Since getResource uses classloader resources, we'll simulate by placing file in classpath
    // Instead, we will test getResourceFile by passing a path to a known resource (this test resource)
    // Because getResourceFile uses classloader.getResource, it won't find tempFile outside classpath.
    // So we create a resource in src/test/resources and test with that.
    // For the purpose of this test, we will test with a known resource "/testresource.txt"
    // Create such a resource file under src/test/resources with content.

    // Use reflection to invoke private method
    Method method = ParseBenchmark.class.getDeclaredMethod("getResourceFile", String.class);
    method.setAccessible(true);

    // Act
    File resourceFile = (File) method.invoke(null, "/testresource.txt");

    // Assert
    assertNotNull(resourceFile);
    assertTrue(resourceFile.isFile());
    assertTrue(resourceFile.getName().endsWith("testresource.txt"));
  }

  @Test
  public void testGetResourceFile_resourceDoesNotExist() throws Exception {
    Method method = ParseBenchmark.class.getDeclaredMethod("getResourceFile", String.class);
    method.setAccessible(true);

    IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> {
      method.invoke(null, "/nonexistent_resource.txt");
    });
    // Because invoke wraps exceptions in InvocationTargetException, unwrap it
    Throwable cause = thrown.getCause();
    assertNotNull(cause);
    assertTrue(cause instanceof IllegalArgumentException);
    assertEquals("Resource /nonexistent_resource.txt does not exist", cause.getMessage());
  }

  @Test
  public void testGetResourceFile_resourceIsNotFile() throws Exception {
    Method method = ParseBenchmark.class.getDeclaredMethod("getResourceFile", String.class);
    method.setAccessible(true);

    // We need a resource that is not a file, e.g. a directory resource or jar resource
    // This is tricky to simulate in unit test.
    // We can try to pass "/" which is usually a directory in resource
    // But getResource("/") may return a directory URL or jar URL.

    // Try with root resource "/"
    IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> {
      method.invoke(null, "/");
    });
    Throwable cause = thrown.getCause();
    assertNotNull(cause);
    assertTrue(cause instanceof IllegalArgumentException);
    assertEquals("Resource / is not a file", cause.getMessage());
  }
}
